from pathlib import Path
import re
p = Path('specs/004-optimize-query-flows/tasks.md')
text = p.read_text()
lines = [line for line in text.splitlines() if line.startswith('- [ ] ')]
pat = re.compile(r'^- \[ \] (T\d{3})(?: \[P\])?(?: \[(US\d+)\])? .+`[^`]+`$')
valid = [line for line in lines if pat.match(line)]
print('total_tasks', len(lines))
from collections import Counter
c=Counter()
for line in lines:
    m=pat.match(line)
    if m:
        c[m.group(2) or 'shared'] += 1
    else:
        c['invalid'] += 1
for key in ['shared','US1','US2','US3','invalid']:
    if c.get(key):
        print(key, c[key])
print('parallel_tasks', sum(' [P] ' in line for line in lines))
if len(valid) != len(lines):
    print('invalid_lines:')
    for line in lines:
        if not pat.match(line):
            print(line)
